:root {
    color-scheme: only light;
    --plyr-color-main: #00aaff;/* ж’ӯж”ҫеҷЁдё»иҰҒйўңиүІ */
    --plyr-control-color: #fff;/* ж’ӯж”ҫеҷЁжҺ§д»¶еӣҫж ҮйўңиүІ */
    --plyr-control-background: transparent;/* ж’ӯж”ҫеҷЁжҺ§д»¶иғҢжҷҜйўңиүІ */
    --plyr-video-background: transparent;/* и§Ҷйў‘иғҢжҷҜйўңиүІ */
    --plyr-range-fill-background: #0099ee;/* иҝӣеәҰжқЎе·ІеЎ«е……йғЁеҲҶзҡ„йўңиүІ */
    --plyr-range-thumb-background: #fff;/* иҝӣеәҰжқЎж»‘еқ—зҡ„йўңиүІ */
}

.plyr {
    height: 100% !important;
    width: 100% !important;
    object-fit: cover;
}

.plyr__video-wrapper * {
    touch-action: none !important;
}

.plyr__video-wrapper video {
    touch-action: none !important;
}

.plyr__controls {
    touch-action: none !important;
}

.plyr__control--overlaid {
    background: transparent;
    border: 0;
    border-radius: 100%;
    color: #fff;
    left: calc(50% - 25px);
    top: calc(50% - 45px);
    transform: none;
    width: 60px;
    height: 48px;
    padding: 0;
    z-index: 2;
}

.plyr__control--overlaid svg {
    width: 50px;
    height: 50px;
    left: calc(50% - 25px);
    top: calc(50% - 10px);
    transform: none;
    fill: #fff;/* еӨ§ж’ӯж”ҫеҷЁжҺ§д»¶еӣҫж ҮйўңиүІ */
    filter: 
        drop-shadow(0 0 20px rgba(0, 0, 0, 0.3))
        drop-shadow(0 0 30px rgba(0, 0, 0, 0.1));
}

.plyr__control--overlaid.hidden {
    display: none !important;
    opacity: 0 !important;
    pointer-events: none !important;
}

.plyr--video .plyr__control.plyr__tab-focus,.plyr--video .plyr__control:hover,.plyr--video .plyr__control[aria-expanded=true] {
    background: transparent;/* ж’ӯж”ҫеҷЁжҺ§д»¶жӮ¬еҒң/зӮ№еҮ»иғҢжҷҜйўңиүІ */
    color: #00aaff;/* ж’ӯж”ҫеҷЁжҺ§д»¶жӮ¬еҒң/зӮ№еҮ»еӣҫж ҮйўңиүІ */
}

.plyr__controls .plyr__controls__item {
    margin-left: auto;
    margin: calc(var(--plyr-control-spacing,10px)/4);
}

.plyr__time--duration {
    display: inline-block !important;
}

.plyr__time+.plyr__time:before {
    margin-right: 8px !important;
}

@media (max-width: 640px) {
    .plyr__captions {
        margin-bottom:-8px
    }

    .plyr__progress__container {
        margin-right: 5px
    }

    .plyr__time {
        position: absolute;
        bottom: 29px;
    }

    .plyr__time--current {
        left: 106px
    }

    .plyr__time+.plyr__time:before {
        content: ""!important
    }

    .plyr__time--duration {
        right: 110px;
    }

    .plyr__volume {
        width: auto;
        max-width: 32px!important;
        min-width: 32px!important
    }

    input[id^=plyr-volume-] {
        display: none!important;
    }

    .plyr--airplay-supported [data-plyr=airplay],.plyr--captions-enabled [data-plyr=captions],.plyr--pip-supported [data-plyr=pip] {
