injectJs:
let sources = [];
let currentSourceIndex = 0;
let currentEpisodeIndex = 0;
let dp = null;
let currentVideoUrl = '';
let autoPlayNext = true;
let currentVodId = '';
let currentVideoDuration = 0;
let progressTimer = null; // е…ЁеұҖе®ҡж—¶еҷЁпјҢзІҫеҮҶжҺ§еҲ¶

// ======== жәҗеҸҳйҮҸзҡ„еӯҳеҸ–ж“ҚдҪң =========
function getSourceVar() {
    if (typeof source !== 'undefined' && source) {
        return String(source.getVariable()) || '';
    }
    return '';
}
function setSourceVar(value) {
    if (typeof source !== 'undefined' && source) {
        source.putVariable(value);
    }
}

// == ж’ӯж”ҫи®°еҪ•з®ЎзҗҶпјҲеӨҡеү§йӣҶ + ж–ӯзӮ№з»ӯж’ӯпјү==
const PROGRESS_SAVE_INTERVAL = 3000; // жҜҸ3з§’дҝқеӯҳдёҖж¬ЎиҝӣеәҰ
const PROGRESS_MIN_SAVE = 2; // жңҖе°ҸдҝқеӯҳиҝӣеәҰпјҢ2з§’е°ұеӯҳпјҢйҒҝе…Қзҹӯж’ӯж”ҫдёҚи®°еҪ•
const PROGRESS_THRESHOLD = 0.95;

function getAllRecords() {
    const varStr = getSourceVar();
    if (!varStr) return {};
    try { return JSON.parse(varStr); } catch (e) { return {}; }
}
function getRecord(vodId) {
    const all = getAllRecords();
    return all[vodId] || null;
}
function saveRecord(vodId, record) {
    const all = getAllRecords();
    all[vodId] = record;
    setSourceVar(JSON.stringify(all));
}
function removeRecord(vodId) {
    const all = getAllRecords();
    delete all[vodId];
    setSourceVar(JSON.stringify(all));
}
function cleanOldRecords() {
    const all = getAllRecords();
    const entries = Object.entries(all);
    if (entries.length > 50) {
        entries.sort((a,b) => (b[1].timestamp||0)-(a[1].timestamp||0));
        const keep = entries.slice(0,50);
        setSourceVar(JSON.stringify(Object.fromEntries(keep)));
    }
}

// ========== ж ёеҝғе·Ҙе…·еҮҪж•°пјҲзІҫеҮҶеӯҳ/жё…иҝӣеәҰпјү==========
function stopProgressTimer() {
    if (progressTimer) {
        clearInterval(progressTimer);
        progressTimer = null;
    }
}

// дҝқеӯҳ**еҪ“еүҚж’ӯж”ҫйӣҶ**зҡ„иҝӣеәҰ
function saveCurrentProgressImmediately() {
    if (!currentVodId || !dp || !sources[currentSourceIndex] || !sources[currentSourceIndex].episodes[currentEpisodeIndex]) {
        return;
    }
    const current = dp.video.currentTime || 0;
    const duration = dp.video.duration || 0;
    // е°ҸдәҺжңҖе°ҸдҝқеӯҳиҝӣеәҰ/и§Ҷйў‘иҝҮзҹӯпјҢдёҚдҝқеӯҳ
    if (current < PROGRESS_MIN_SAVE || duration < 5) return;

    // еҸӘдҝқеӯҳ**еҪ“еүҚйӣҶ**зҡ„иҝӣеәҰпјҢејәеҲ¶з”Ёе…ЁеұҖеҪ“еүҚзҡ„йӣҶж•°/зәҝи·ҜпјҢжқңз»қдёІеҖј
    const record = {
        sourceIndex: currentSourceIndex,
        episodeIndex: currentEpisodeIndex,
        episodeName: sources[currentSourceIndex].episodes[currentEpisodeIndex].name,
        progress: (current/duration) > PROGRESS_THRESHOLD ? 0 : current,
        duration: duration,
        timestamp: Date.now() // ж—¶й—ҙжҲіпјҢзЎ®дҝқжңҖж–°и®°еҪ•
    };
    saveRecord(currentVodId, record);
}
function extractVodIdFromSourceContainer() {
    const html = $('#source-container').html() || '';
    const match = html.match(/"id":"(\d+)"/) || html.match(/\/id\/(\d+)/);
    return match ? match[1] : '';
}
// гҖҗж ёеҝғдҝ®еӨҚгҖ‘йҮҚиҝӣж—¶**дёҘж јж ЎйӘҢи®°еҪ•зҡ„йӣҶж•°+ж—¶й—ҙжҲі**пјҢеҸӘеҠ иҪҪеҜ№еә”йӣҶзҡ„жңҖж–°иҝӣеәҰ
function playFromRecordOrFirstEpisode() {
    if (!currentVodId) { 
        playEpisode(0,0, false, 0); 
        return; 
    }
    const record = getRecord(currentVodId);
    // дёҘж јж ЎйӘҢпјҡи®°еҪ•еӯҳеңЁ+еҜ№еә”йӣҶж•°жңүж•ҲпјҢжүҚжҒўеӨҚиҝӣеәҰ
    if (record && sources[record.sourceIndex] && sources[record.sourceIndex].episodes[record.episodeIndex]) {
        currentSourceIndex = record.sourceIndex;
        currentEpisodeIndex = record.episodeIndex;
        $('.tab-btn').removeClass('active').eq(record.sourceIndex).addClass('active');
        initPlaylist();
        // еҸӘжҒўеӨҚ**иҜҘи®°еҪ•еҜ№еә”йӣҶ**зҡ„иҝӣеәҰпјҢзІҫеҮҶеҢ№й…Қ
        playEpisode(record.sourceIndex, record.episodeIndex, false, record.progress);
        showError(`е·ІжҒўеӨҚеҺҶеҸІж’ӯж”ҫпјҡ${record.episodeName} ${formatTime(record.progress)}`);
    } else {
        playEpisode(0,0, false, 0);
    }
}

// ========== йЎөйқўеҲқе§ӢеҢ– ==========
$(document).ready(function() {
    sources = parseSourcesFromHTML();
    currentVodId = extractVodIdFromSourceContainer();
    if (sources.length === 0) {
        $('#playlistContainer').html('<div class="error-msg show">жңӘжүҫеҲ°ж’ӯж”ҫеҲ—иЎЁж•°жҚ®</div>');
        return;
    }
    initTabs();
    initPlaylist();
    playFromRecordOrFirstEpisode();
});

// ========== зәҝи·Ҝ/ж’ӯж”ҫеҲ—иЎЁеҲқе§ӢеҢ–пјҲеҲҮйӣҶеҚіж—¶еӯҳиҝӣеәҰпјү==========
function initTabs() {
    const $tabs = $('#sourceTabs'); $tabs.empty();
    sources.forEach((src, index) => {
        const $btn = $('<button>').addClass('tab-btn').text(src.name).toggleClass('active', index===0);
        $btn.on('click', function() {
            // еҲҮзәҝи·ҜпјҡејәеҲ¶еӯҳеҪ“еүҚиҝӣеәҰ+жё…е®ҡж—¶еҷЁпјҢж–°зәҝи·Ҝд»ҺеӨҙж’ӯ
            stopProgressTimer();
            saveCurrentProgressImmediately();
            $('.tab-btn').removeClass('active'); $(this).addClass('active');
            currentSourceIndex = index; currentEpisodeIndex = 0;
            initPlaylist();
            playEpisode(currentSourceIndex, currentEpisodeIndex, true, 0);
        });
        $tabs.append($btn);
    });
    addAutoPlayToggle();
}
function addAutoPlayToggle() {
    const $toggle = $('<button>').addClass('tab-btn').css({marginLeft:'auto',background:autoPlayNext?'#ff6b6b':'#666',fontSize:'12px'})
        .text(autoPlayNext?'иҝһж’ӯ: ејҖ':'иҝһж’ӯ: е…і').on('click', function() {
            autoPlayNext = !autoPlayNext;
            $(this).text(autoPlayNext?'иҝһж’ӯ: ејҖ':'иҝһж’ӯ: е…і').css('background',autoPlayNext?'#ff6b6b':'#666');
            showError(autoPlayNext?'е·ІејҖеҗҜиҮӘеҠЁиҝһж’ӯ':'е·Іе…ій—ӯиҮӘеҠЁиҝһж’ӯ');
            updateAutoPlayStatus();
        });
    $('#sourceTabs').append($toggle);
}
function updateAutoPlayStatus() {
    $('#autoPlayStatus').text(autoPlayNext?'иҮӘеҠЁиҝһж’ӯејҖеҗҜ':'иҮӘеҠЁиҝһж’ӯе…ій—ӯ').css('color',autoPlayNext?'#4ecdc4':'#888');
}
// гҖҗж ёеҝғдҝ®еӨҚгҖ‘ж’ӯж”ҫеҲ—иЎЁиҝӣеәҰжқЎ**дёҘж јеҢ№й…Қи®°еҪ•зҡ„йӣҶж•°**пјҢз»қдёҚжҳҫзӨәй”ҷйӣҶиҝӣеәҰ
function initPlaylist() {
    const $container = $('#playlistContainer'); const $errorMsg = $('#errorMsg').detach();
    $container.empty().append($errorMsg);
    const currentSource = sources[currentSourceIndex];
    const record = currentVodId ? getRecord(currentVodId) : null; // еҸӘеҸ–еҪ“еүҚи§Ҷйў‘зҡ„и®°еҪ•

    let recordTip = '';
    // и®°еҪ•жҸҗзӨәеҸӘжҳҫзӨә**еҪ“еүҚи§Ҷйў‘жңҖеҗҺж’ӯж”ҫйӣҶ**зҡ„иҝӣеәҰ
    if (record && (record.sourceIndex!==currentSourceIndex || record.episodeIndex!==currentEpisodeIndex)) {
        const progressText = record.progress>0 ? ` (${formatTime(record.progress)})` : '';
        recordTip = `<span style="color:#ff6b6b;margin-left:8px;cursor:pointer;" onclick="resumeFromRecord()">в–¶ дёҠж¬ЎзңӢеҲ°${record.episodeName}${progressText}</span>`;
    }
    $container.append(`
        <div class="now-playing">
            <span class="label">еҪ“еүҚзәҝи·Ҝ:</span><span class="source-name">${currentSource.name}</span>
            <span style="margin:0 5px;">|</span><span class="label">йҖүдёӯ:</span><span id="currentEpiText">${currentSource.episodes[currentEpisodeIndex]?.name||''}</span>
            <span style="margin:0 5px;">|</span><span id="autoPlayStatus" style="color:${autoPlayNext?'#4ecdc4':'#888'};font-size:12px;">${autoPlayNext?'иҮӘеҠЁиҝһж’ӯејҖеҗҜ':'иҮӘеҠЁиҝһж’ӯе…ій—ӯ'}</span>
            ${recordTip}
        </div>
    `);
    $container.append(`<div class="playlist-title"><span>ж’ӯж”ҫеҲ—иЎЁ</span><span class="episode-count">е…ұ ${currentSource.episodes.length} йӣҶ</span></div>`);
    const $grid = $('<div>').addClass('episode-grid');

    currentSource.episodes.forEach((ep, idx) => {
        const $btn = $('<button>').addClass('episode-btn').text(ep.name).toggleClass('playing', idx===currentEpisodeIndex);
        // гҖҗе…ій”®гҖ‘еҸӘжңү**еҪ“еүҚи®°еҪ•зҡ„йӣҶж•°**пјҢжүҚжҳҫзӨәиҝӣеәҰжқЎпјҢе…¶д»–йӣҶз»қдёҚжҳҫзӨә
        if (record && record.sourceIndex === currentSourceIndex && record.episodeIndex === idx) {
            $btn.css('border', '2px solid #ff6b6b');
            if (record.progress > 0 && record.duration > 0) {
                const percent = Math.min((record.progress / record.duration) * 100, 100);
                const isFinished = percent > 95;
                $btn.css('position', 'relative');
                $btn.append(`
                    <div style="
                        position: absolute;
                        bottom: 0;
                        left: 0;
                        height: 3px;
                        background: ${isFinished ? '#4ecdc4' : '#ff6b6b'};
                        width: ${isFinished ? 100 : percent}%;
                    "></div>
                    <span style="
                        position: absolute;
                        top: 2px;
                        right: 2px;
                        font-size: 9px;
                        color: ${isFinished ? '#4ecdc4' : '#ff6b6b'};
                        background: rgba(0,0,0,0.7);
                        padding: 1px 3px;
                        border-radius: 3px;
                    ">${isFinished ? 'е·ІзңӢе®Ң' : formatTime(record.progress)}</span>
                `);
            } else {
                $btn.append('<span style="position:absolute;top:2px;right:2px;font-size:10px;color:#ff6b6b;">дёҠж¬Ў</span>');
            }
        }
        $btn.on('click', function() {
            // еҲҮйӣҶпјҡеҚіж—¶еӯҳеҪ“еүҚиҝӣеәҰ+жё…е®ҡж—¶еҷЁпјҢж–°йӣҶејәеҲ¶0з§’д»ҺеӨҙж’ӯ
            stopProgressTimer();
            saveCurrentProgressImmediately();
            currentEpisodeIndex = idx;
            initPlaylist();
            playEpisode(currentSourceIndex, currentEpisodeIndex, true, 0);
        });
        $grid.append($btn);
    });
    $container.append($grid);
}

// ========== жүӢеҠЁжҒўеӨҚеҺҶеҸІи®°еҪ•пјҲзІҫеҮҶеҢ№й…ҚйӣҶж•°пјү==========
function resumeFromRecord() {
    const record = getRecord(currentVodId);
    if (!record) return;
    if (sources[record.sourceIndex] && sources[record.sourceIndex].episodes[record.episodeIndex]) {
        // жҒўеӨҚеүҚе…ҲдҝқеӯҳеҪ“еүҚж’ӯж”ҫзҡ„иҝӣеәҰпјҢйҒҝе…ҚдёўеӨұ
        stopProgressTimer();
        saveCurrentProgressImmediately();
        currentSourceIndex = record.sourceIndex; currentEpisodeIndex = record.episodeIndex;
        $('.tab-btn').removeClass('active').eq(record.sourceIndex).addClass('active');
        initPlaylist();
        // еҸӘжҒўеӨҚиҜҘи®°еҪ•еҜ№еә”йӣҶзҡ„иҝӣеәҰ
        playEpisode(currentSourceIndex, currentEpisodeIndex, false, record.progress);
        const progressText = record.progress>0 ? ` (${formatTime(record.progress)})` : '';
        showError(`е·ІжҒўеӨҚиҮі: ${record.episodeName}${progressText}`);
    }
}
// ж—¶й—ҙж јејҸеҢ–
function formatTime(seconds) {
    if (!seconds || seconds<0) return '00:00';
    const h = Math.floor(seconds/3600); const m = Math.floor((seconds%3600)/60); const s = Math.floor(seconds%60);
    return h>0 ? `${h}:${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}` : `${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
}

// ========== ж’ӯж”ҫж ёеҝғеҮҪж•°пјҲеҲҮйӣҶ0з§’пјҢйҮҚиҝӣзІҫеҮҶеҠ иҪҪеҜ№еә”иҝӣеәҰпјү==========
function playEpisode(sourceIdx, episodeIdx, showTip=false, resumeProgress=0) {
    // ж’ӯж”ҫж–°йӣҶеүҚпјҢејәеҲ¶дҝқеӯҳдёҠдёҖйӣҶиҝӣеәҰпјҢжқңз»қиҝӣеәҰдёўеӨұ/дёІйӣҶ
    stopProgressTimer();
    saveCurrentProgressImmediately();

    // ејәеҲ¶жӣҙж–°е…ЁеұҖеҪ“еүҚйӣҶж•°пјҢзЎ®дҝқеҗҺз»ӯдҝқеӯҳиҝӣеәҰзІҫеҮҶ
    currentSourceIndex = sourceIdx; 
    currentEpisodeIndex = episodeIdx;

    const src = sources[sourceIdx]; 
    const episode = src.episodes[episodeIdx];
    if (!episode) return; // йӣҶж•°ж— ж•ҲпјҢзӣҙжҺҘиҝ”еӣһ

    $('#currentEpiText').text(episode.name);
    $('.episode-btn').removeClass('playing').eq(episodeIdx).addClass('playing');
    showLoading(true); hideError(); hideUrlTip();
    showError('жӯЈеңЁи§Јжһҗж’ӯж”ҫең°еқҖпјҢиҜ·зЁҚеҖҷ...');

    $.ajax({
        url: episode.url, type:'GET', dataType:'html', timeout:15000,
        success: function(html) {
            showLoading(false); hideError();
            if (!currentVodId) currentVodId = extractVodId(html);
            // еҸӘдҪҝз”ЁеӨ–йғЁдј е…Ҙзҡ„иҝӣеәҰпјҢеҲҮйӣҶдј 0еҲҷ0пјҢжҒўеӨҚи®°еҪ•дј еӨҡе°‘еҲҷеӨҡе°‘пјҢз»қдёҚиҮӘеҠЁиҜ»е…¶д»–иҝӣеәҰ
            let startProgress = resumeProgress;
            parseAndPlay(html, showTip, startProgress);
        },
        error: function(xhr, status, error) {
            showLoading(false);
            showError(status==='timeout'?'иҜ·жұӮи¶…ж—¶пјҢиҜ·е°қиҜ•еҲҮжҚўзәҝи·ҜжҲ–еҲ·ж–°йЎөйқў':xhr.status===404?'ж’ӯж”ҫйЎөйқўдёҚеӯҳеңЁпјҢиҜ·е°қиҜ•е…¶д»–зәҝи·Ҝ':'иҺ·еҸ–ж’ӯж”ҫең°еқҖеӨұиҙҘпјҢиҜ·е°қиҜ•еҲҮжҚўзәҝи·Ҝ');
        }
    });
}
function extractVodId(html) {
    if (currentVodId) return currentVodId;
    const match = html.match(/"id":"(\d+)"/); if (match) return match[1];
    const urlMatch = html.match(/\/id\/(\d+)/); if (urlMatch) return urlMatch[1];
    return '';
}
function parseAndPlay(html, showTip=false, startProgress=0) {
    try {
        const match = html.match(/var\s+player_aaaa\s*=\s*(\{.+?\})[\s;]*</);
        if (!match) { showError('жңӘжүҫеҲ°ж’ӯж”ҫеҷЁж•°жҚ®пјҢиҜҘзәҝи·ҜеҸҜиғҪжҡӮдёҚеҸҜз”Ё'); return; }
        let jsonStr = match[1].replace(/\\/g,"").trim();
        let playerData; try { playerData = JSON.parse(jsonStr); } catch(e) { showError('ж•°жҚ®и§ЈжһҗеӨұиҙҘпјҢиҜ·е°қиҜ•еҲҮжҚўе…¶д»–зәҝи·Ҝ'); return; }
        if (!currentVodId && playerData.id) currentVodId = String(playerData.id);
        const videoUrl = playerData.url; if (!videoUrl) { showError('жңӘжүҫеҲ°и§Ҷйў‘й“ҫжҺҘпјҢиҜҘзәҝи·ҜеҸҜиғҪжҡӮдёҚеҸҜз”Ё'); return; }
        currentVideoUrl = videoUrl;
        if (showTip) showUrlTip(videoUrl, '#playlistContainer');
        isDirectVideo(videoUrl) ? playWithDPlayer(videoUrl, playerData, startProgress) : playWithIframe(videoUrl);
    } catch(e) { showError('и§ЈжһҗејӮеёёпјҢиҜ·е°қиҜ•еҲҮжҚўзәҝи·Ҝпјҡ' + e.message.substring(0,50)); }
}
function isDirectVideo(url) {
    const lowerUrl = url.toLowerCase();
    return ['.mp4','.m3u8','.flv'].some(ext => lowerUrl.includes(ext));
}

// ========== DPlayerж’ӯж”ҫпјҲзІҫеҮҶжҢүдј е…ҘиҝӣеәҰж’ӯж”ҫпјҢе®һж—¶еӯҳеҪ“еүҚиҝӣеәҰпјү==========
function playWithDPlayer(url, playerData, startProgress=0) {
    // й”ҖжҜҒж—§ж’ӯж”ҫеҷЁпјҢжқңз»қж—§ж’ӯж”ҫеҷЁзҡ„иҝӣеәҰе№Іжү°
    if (dp) { 
        dp.destroy(); 
        dp = null; 
    }
    $('#iframe-container').hide(); $('#dplayer').show(); hideUrlTip();
    const isM3U8 = url.toLowerCase().includes('.m3u8');
    dp = new DPlayer({
        container: document.getElementById('dplayer'),
        video: { url: url, type: isM3U8?'hls':'auto', pic: playerData.pic||'' },
        autoplay: true, theme: '#ff6b6b', lang: 'zh-cn', hotkey: true, preload: 'auto', volume: 0.8,
        playbackSpeed: [0.5,0.75,1,1.25,1.5,2]
    });
    let hasSeeked = false;

    // и§Ҷйў‘е…ғж•°жҚ®еҠ иҪҪе®ҢжҲҗеҗҺпјҢзІҫеҮҶи·іиҪ¬еҲ°дј е…Ҙзҡ„иҝӣеәҰпјҲеҸӘи·іеҪ“еүҚйӣҶзҡ„пјү
    dp.on('loadedmetadata', function() {
        currentVideoDuration = dp.video.duration || 0;
        if (startProgress > 0 && currentVideoDuration > 0) {
            const safeProgress = Math.min(startProgress, currentVideoDuration-2);
            if (safeProgress > 0) { 
                dp.seek(safeProgress); 
                hasSeeked = true; 
                showError(`е·Ід»Һ ${formatTime(safeProgress)} з»§з»ӯж’ӯж”ҫ`); 
            }
        }
    });
    // ж’ӯж”ҫж—¶еҗҜеҠЁе®ҡж—¶еҷЁпјҢе®һж—¶дҝқеӯҳ**еҪ“еүҚйӣҶ**иҝӣеәҰ
    dp.on('play', function() {
        stopProgressTimer();
        progressTimer = setInterval(() => { saveCurrentProgressImmediately(); }, PROGRESS_SAVE_INTERVAL);
    });
    // жҡӮеҒңж—¶еҚіж—¶дҝқеӯҳиҝӣеәҰпјҢйҒҝе…ҚйҖҖеҮәдёўеӨұ
    dp.on('pause', function() {
        stopProgressTimer();
        saveCurrentProgressImmediately();
    });
    // иҝӣеәҰжӣҙж–°ж—¶пјҢеҸӘж ЎжӯЈ**еҪ“еүҚйӣҶ**зҡ„жҒўеӨҚиҝӣеәҰпјҢз»қдёҚдёІйӣҶ
    dp.on('timeupdate', function() {
        if (!hasSeeked && startProgress > 0 && dp.video.currentTime < 3) {
            dp.seek(startProgress);
            hasSeeked = true;
        }
    });
    // е…ЁеұҸ/йҖҖеҮәе…ЁеұҸйҖӮй…Қ
    dp.on('fullscreen', function() {
        if (screen.orientation && screen.orientation.lock) {
            screen.orientation.lock('landscape').catch(()=>{screen.orientation.lock('any').catch(()=>{});});
        }
    });
    dp.on('fullscreen_cancel', function() {
        if (screen.orientation && screen.orientation.unlock) screen.orientation.unlock().catch(()=>{});
    });
    // M3U8и§Ҷйў‘йҖӮй…Қ
    if (isM3U8 && Hls.isSupported()) {
        dp.video.type = 'customHls';
        dp.video.customType = {
            customHls: function(video) { const hls = new Hls(); hls.loadSource(video.src); hls.attachMedia(video); }
        };
    }
    // ж’ӯж”ҫй”ҷиҜҜжҸҗзӨә
    setTimeout(() => {
        dp.on('error', function() { showError('и§Ҷйў‘ж’ӯж”ҫеӨұиҙҘпјҢиҜ·е°қиҜ•еҲҮжҚўзәҝи·ҜжҲ–еү§йӣҶ'); });
    }, 10000);
    // и§Ҷйў‘ж’ӯж”ҫе®ҢжҜ•
    dp.on('ended', function() {
        stopProgressTimer();
        saveCurrentProgressImmediately();
        if (autoPlayNext) playNextEpisode();
        else showError('жң¬йӣҶе·Із»“жқҹпјҢиҮӘеҠЁиҝһж’ӯе·Іе…ій—ӯ');
    });
    // йЎөйқўе…ій—ӯ/еҲ·ж–°ж—¶пјҢејәеҲ¶дҝқеӯҳеҪ“еүҚиҝӣеәҰпјҢиҝҷжҳҜе…ій”®пјҒ
    window.addEventListener('beforeunload', function() {
        stopProgressTimer();
        saveCurrentProgressImmediately();
    });
    // зӮ№еҮ»ж’ӯж”ҫеҷЁжҳҫзӨәи§Ҷйў‘ең°еқҖ
    $('#dplayer').off('click').on('click', function(e) {
        if ($(e.target).closest('.dplayer-controller, .dplayer-mask, #video-url-tip').length) return;
        showUrlTip(url, '#dplayer');
    });
}

// ========== иҮӘеҠЁиҝһж’ӯдёӢдёҖйӣҶпјҲејәеҲ¶0з§’д»ҺеӨҙж’ӯпјү==========
function playNextEpisode() {
    const currentSource = sources[currentSourceIndex];
    const nextIndex = currentEpisodeIndex+1;
    if (nextIndex < currentSource.episodes.length) {
        showError(`еҚіе°Ҷж’ӯж”ҫдёӢдёҖйӣҶ: ${currentSource.episodes[nextIndex].name}`);
        // иҮӘеҠЁиҝһж’ӯд№ҹејәеҲ¶0з§’пјҢд»ҺеӨҙж’ӯж”ҫдёӢдёҖйӣҶ
        setTimeout(() => { playEpisode(currentSourceIndex, nextIndex, false, 0); }, 1500);
    } else {
        showError('жң¬зәҝи·Ҝе·Іж’ӯж”ҫе®ҢжҜ•');
        $('#autoPlayStatus').text('жң¬зәҝи·Ҝе®Ңз»“').css('color','#ff6b6b');
        cleanOldRecords();
    }
}

// ========== еӨ–йғЁж’ӯж”ҫеҷЁiframeж’ӯж”ҫ ==========
function playWithIframe(url) {
    if (dp) { dp.destroy(); dp = null; }
    $('#dplayer').hide(); const $container = $('#iframe-container'); $container.empty().show();
    const $loading = $(`<div class="loading show" style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);"><div class="spinner"></div><div>еҠ иҪҪеӨ–йғЁж’ӯж”ҫеҷЁ...</div></div>`);
    $container.append($loading);
    const $iframe = $('<iframe>').attr('src','https://jx.quanmingjiexi.com/?url='+url).attr('allowfullscreen','true').attr('frameborder','0').css({width:'100%',height:'100%',opacity:'0'}).on('load',function(){$loading.remove();$(this).css('opacity','1');});
    setTimeout(() => { $loading.remove(); $iframe.css('opacity','1'); }, 5000);
    $container.append($iframe);
}

// ========== еҹәзЎҖе·Ҙе…·еҮҪж•° ==========
function showLoading(show) { $('#player-loading').toggleClass('show', show); }
function showError(msg) { $('#errorMsg').text(msg).addClass('show'); setTimeout(()=>$('#errorMsg').removeClass('show'),3000); }
function hideError() { $('#errorMsg').removeClass('show'); }
// е…ЁеұҸеҸҳеҢ–йҖӮй…Қ
document.addEventListener('fullscreenchange', () => {
    if (document.fullscreenElement) {
        if (screen.orientation && screen.orientation.lock) screen.orientation.lock('landscape').catch(()=>{screen.orientation.lock('any').catch(()=>{});});
    } else {
        if (screen.orientation && screen.orientation.unlock) screen.orientation.unlock().catch(()=>{});
    }
});
// еұҸе№•ж—ӢиҪ¬йҖӮй…Қж’ӯж”ҫеҷЁеӨ§е°Ҹ
window.addEventListener('orientationchange', () => { setTimeout(()=>dp&&dp.resize(),300); });
// жҳҫзӨәи§Ҷйў‘ең°еқҖжҸҗзӨә
function showUrlTip(url, container) {
    hideUrlTip(); if (window.urlTipTimeout) clearTimeout(window.urlTipTimeout);
    const $tip = $(`<div id="video-url-tip" style="position:absolute;top:0;left:0;background:rgba(0,0,0,0.6);color:#fff;padding:8px 12px;font-size:12px;z-index:1000;max-width:100%;word-break:break-all;"><div style="user-select:text;line-height:1.5;">${url}</div></div>`);
    $(container||'body').append($tip);
    window.urlTipTimeout = setTimeout(()=>{hideUrlTip();},3000);
}
function hideUrlTip() { $('#video-url-tip').remove(); if (window.urlTipTimeout) clearTimeout(window.urlTipTimeout); window.urlTipTimeout=null; }
// иҜҰжғ…еұ•ејҖ/ж”¶иө·
function toggleDetail() {
    const content = document.getElementById('detailContent');
    const btn = document.querySelector('#info .toggle-btn');
    content.classList.toggle('show');
    btn.classList.toggle('active');
    btn.innerHTML = content.classList.contains('show') ? 'ж”¶иө·иҜҰжғ… <span style="color:inherit">в–І</span>' : 'жҹҘзңӢиҜҰжғ… <span style="color:#ff6b6b">в–ј</span>';
}
// и§Јжһҗж’ӯж”ҫжәҗе’Ңеү§йӣҶ
function parseSourcesFromHTML() {
    const sources = [];
    $('.stui-pannel-box').each(function() {
        const $box = $(this);
        const sourceName = $box.find('.title').text().trim();
        const episodes = [];
        $box.find('.stui-content__playlist li a').each(function() {
            const $a = $(this);
            episodes.push({name:$a.text().trim(), url:$a.attr('href')});
        });
        if (episodes.length>0) sources.push({name:sourceName, episodes:episodes});
    });
    return sources;
}

