#info {
    background: #1a1a1a;
    margin: 10px 15px;
    border-radius: 12px;
    overflow: hidden;
    border: 1px solid #333;
}

#info .toggle-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    width: 100%;
    padding: 12px 20px;
    background: #252525;
    color: #fff;
    border: none;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    transition: all 0.3s ease;
}

#info .toggle-btn:hover {
    background: #2f2f2f;
}

#info .toggle-btn::after {
    content: 'в–ј';
    font-size: 10px;
    color: #ff6b6b;
    transition: transform 0.3s ease;
}

#info .toggle-btn.active::after {
    transform: rotate(180deg);
}

#info .toggle-btn.active {
    background: #ff6b6b;
    color: #fff;
}

#info .toggle-btn.active::after {
    color: #fff;
}

#info .detail-content {
    max-height: 0;
    overflow: hidden;
    transition: max-height 0.4s ease, opacity 0.3s ease;
    opacity: 0;
    background: #1a1a1a;
}

#info .detail-content.show {
    max-height: 800px;
    opacity: 1;
}

/* иҜҰжғ…еҶ…йғЁж ·ејҸ - е…ЁйғЁеҠ еүҚзјҖйҒҝе…ҚеҶІзӘҒ */
#info .detail-inner {
    padding: 15px;
}

#info .detail-title {
    font-size: 18px;
    color: #fff;
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 8px;
    flex-wrap: wrap;
    line-height: 1.4;
}

#info .detail-score {
    background: #ff6b6b;
    color: white;
    padding: 2px 8px;
    border-radius: 12px;
    font-size: 12px;
    font-weight: bold;
    flex-shrink: 0;
}

#info .detail-row {
    margin-bottom: 10px;
    font-size: 13px;
    line-height: 1.7;
    color: #ccc;
}

#info .detail-label {
    color: #888;
    margin-right: 5px;
}

#info .detail-row a {
    color: #4a9eff;
    text-decoration: none;
    margin-right: 6px;
    transition: color 0.2s;
}

#info .detail-row a:hover {
    color: #6ab3ff;
    text-decoration: underline;
}

#info .detail-split {
    display: inline-block;
    width: 1px;
    height: 10px;
    background: #444;
    margin: 0 8px;
    vertical-align: middle;
}

#info .detail-desc {
    background: #252525;
    padding: 12px;
    border-radius: 8px;
    margin-top: 12px;
    border-left: 3px solid #ff6b6b;
    font-size: 13px;
    line-height: 1.8;
    color: #bbb;
}

#info .detail-desc-label {
    display: block;
    color: #ff6b6b;
    margin-bottom: 6px;
    font-weight: 500;
}

/* йҡҗи—Ҹе…ғзҙ  */
#info .hidden-xs {
    display: inline;
}

@media (max-width: 480px) {
    #info .hidden-xs {
        display: none !important;
    }

    #info {
        margin: 8px;
    }

    #info .detail-inner {
        padding: 12px;
    }
}

/* иҜҰжғ…еҢәеҹҹaж Үзӯҫж ·ејҸ - зҒ°иүІдёҚеҲәзңј */
#info a {
    color: #888 !important;
    text-decoration: none !important;
    pointer-events: none; /* йҳ»жӯўзӮ№еҮ» */
    cursor: default;
    margin-right: 6px;
}

#info a:hover {
    color: #888 !important;
    text-decoration: none !important;
}

