@js:
let urls = [];
let resultStr = String(result);

let getM3u8 = (html = resultStr) => {
    let url = /(https?:[^'"\s]*?\.m3u8[^'"\s]*)/g;
    let urlSet = new Set();
    for (let match of (html.matchAll(url) || [])) {
  	   let ul = match[1].replace(/\\/g, "");
  	   urlSet.add(ul);
    	};
    return Array.from(urlSet);
};

 let updateProgress = (current, total) => {
    let percentage = Math.round(current / total * 10000)/100;
    let blocks = Math.floor(percentage / 10);
    let progressBar = "в–Ҳ".repeat(blocks) + "в–‘".repeat(10 - blocks);
    java.longToast(`гҖҗеҠ иҪҪиҝӣеәҰгҖ‘\n${progressBar} \n${percentage}%`);
};

if (/зӮ№жҲ‘/.test(result) && /жҹҘзңӢиҜҰжғ…/.test(result)) {
    let list = java.getElements('@@#post>article>.post-content>p>a');
    let links = Array.from(list).slice(0,-1);
    let tempUrls = []; 
    links.forEach((link, index) => {
        updateProgress(index + 1, links.length);

        let href = String(link.attr('href'));
        let fullUrl = `${source.key}${href}`;
        let doc = String(java.ajax(fullUrl));
        let pageUrls = getM3u8(doc);
        if (pageUrls.length > 0) {
            tempUrls = tempUrls.concat(pageUrls);
        }
        if (index === links.length - 1) {
            urls = tempUrls;
        }
    })
} else {
    urls = getM3u8();
};

`<html>
    <head>
        <meta name="viewport" content="width=device-width">
        <style>
            body {
                margin: 0;
                font-family: Arial, sans-serif;
                background: linear-gradient(135deg, #ece9e6, #ffffff);
                display: flex;
                flex-direction: column;
                align-items: center;
                justify-content: flex-start;
                padding: 20px;
            }
            .container {
                width: 100%;
                max-width: 800px;
                background: #fff;
                border-radius: 10px;
                box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
                overflow: hidden;
                margin-bottom: 20px;
            }
            h3 {
            	    text-align: center;
                margin: 0;
                padding: 10px 20px;
                font-size: 0.9em;
                background: #333;
                color: #fff;
                border-radius: 10px 10px 0 0;
            }
            .video-container {
                width: 100%;
                background: #000;
                position: relative;
            }
            video {
                width: 100%;
                height: auto;
                display: block;
            }
            .info-container {
                padding: 20px;
            }
            .info-container p {
                margin: 10px 0;
                color: #555;
            }
            .info-container p span {
                font-weight: bold;
                color: #000;
            }
            .nav-container {
                display: flex;
                justify-content: space-between;
                align-items: center;
                padding: 15px 20px;
                background: #f5f5f5;
                border-top: 1px solid #ddd;
            }
            .nav-button {
                padding: 10px 20px;
                background: #007bff;
                color: white;
                border: none;
                border-radius: 5px;
                cursor: pointer;
                font-size: 14px;
            }
            .nav-button:disabled {
                background: #6c757d;
                cursor: not-allowed;
            }
            .page-select {
                padding: 10px 15px;
                border: 1px solid #ddd;
                border-radius: 5px;
                font-size: 14px;
                background: white;
                min-width: 120px;
            }
            .video-info {
                text-align: center;
                padding: 10px;
                background: #f8f9fa;
                border-bottom: 1px solid #ddd;
                font-size: 14px;
                color: #666;
            }
        </style>
    </head>
    <body>
        <div class="container">
        <h3>еҪ“еүҚж’ӯж”ҫ: з¬¬<span id="currentVideo">1</span>йӣҶ / е…ұ${urls.length}йӣҶ</h3>
            <div class="video-container">
                <video controls autoplay name="media" id="videoPlayer">
                    <source src="${urls[0] || ''}" type="application/x-mpegURL">
                </video>
            </div>
            <div class="nav-container">
                <button class="nav-button" id="prevBtn" onclick="changeVideo(-1)">дёҠдёҖйӣҶ</button>
                <select class="page-select" id="pageSelect">
                    <!-- йҖүйЎ№е°ҶйҖҡиҝҮJavaScriptеҠЁжҖҒз”ҹжҲҗ -->
                </select>
                <button class="nav-button" id="nextBtn" onclick="changeVideo(1)">дёӢдёҖйӣҶ</button>
            </div>
            <div class="info-container">
            </div>
        </div>

        <script>
            // и§Ҷйў‘ең°еқҖж•°з»„е’ҢеҪ“еүҚзҙўеј•
            const videoUrls = ${JSON.stringify(urls)};
            let currentVideoIndex = 0;

            // иҺ·еҸ–DOMе…ғзҙ 
            const video = document.getElementById('videoPlayer');
            const prevBtn = document.getElementById('prevBtn');
            const nextBtn = document.getElementById('nextBtn');
            const pageSelect = document.getElementById('pageSelect');
            const currentVideoSpan = document.getElementById('currentVideo');

            // з”ҹжҲҗдёӢжӢүиҸңеҚ•йҖүйЎ№
            function generateSelectOptions() {
                let optionsHtml = '';
                for (let i = 0; i < videoUrls.length; i++) {
                   optionsHtml += '<option value="' + i + '">з¬¬' + (i + 1) + 'йӣҶ</option>';
    };
                pageSelect.innerHTML = optionsHtml;
             }

            // жӣҙж–°жҢүй’®зҠ¶жҖҒе’ҢжҳҫзӨә
            function updateButtons() {
                prevBtn.disabled = currentVideoIndex === 0;
                nextBtn.disabled = currentVideoIndex === videoUrls.length - 1;
                pageSelect.value = currentVideoIndex;
                currentVideoSpan.textContent = currentVideoIndex + 1;
            }

            // еҲҮжҚўи§Ҷйў‘
            function changeVideo(direction) {
                const newIndex = currentVideoIndex + direction;
                if (newIndex >= 0 && newIndex < videoUrls.length) {
                    currentVideoIndex = newIndex;
                    video.src = videoUrls[currentVideoIndex];
                    video.load();
                    updateButtons();
                }
            }

            // йҖүжӢ©зү№е®ҡи§Ҷйў‘
            function selectVideo(index) {
                const newIndex = parseInt(index);
                if (newIndex >= 0 && newIndex < videoUrls.length) {
                    currentVideoIndex = newIndex;
                    video.src = videoUrls[currentVideoIndex];
                    video.load();
                    updateButtons();
                }
            }

            // еҲқе§ӢеҢ–жҢүй’®зҠ¶жҖҒ
            generateSelectOptions();
            updateButtons();

            // з»‘е®ҡдёӢжӢүиҸңеҚ•дәӢд»¶
            pageSelect.addEventListener('change',function() {
               selectVideo(this.value);
             });

            // и§Ұж‘ёжҺ§еҲ¶зӣёе…ід»Јз Ғ
            let touchStartX = 0;
            let touchStartY = 0;
            let touchStartTime = 0;
            let isLongPress = false;

            // ж»‘еҠЁеҝ«иҝӣ
            video.addEventListener('touchstart', (e) => {
                touchStartX = e.touches[0].clientX;
                touchStartY = e.touches[0].clientY;
                touchStartTime = Date.now();
                isLongPress = false;
            });

            video.addEventListener('touchmove', (e) => {
                const deltaX = e.touches[0].clientX - touchStartX;
                const deltaY = e.touches[0].clientY - touchStartY;

                // еҰӮжһңжҳҜж°ҙе№іж»‘еҠЁпјҢдё”жңӘиҝӣе…Ҙй•ҝжҢүзҠ¶жҖҒ
                if (Math.abs(deltaX) > Math.abs(deltaY) && !isLongPress) {
                    const duration = video.duration;
                    const seekTime = video.currentTime + (deltaX / 100); // жҜҸж»‘еҠЁ100pxеҝ«иҝӣ1з§’
                    video.currentTime = Math.min(Math.max(seekTime, 0), duration);
                }
            });

            // й•ҝжҢүеҝ«иҝӣ
            video.addEventListener('touchend', (e) => {
                const touchEndTime = Date.now();
                const touchDuration = touchEndTime - touchStartTime;

                // еҰӮжһңй•ҝжҢүж—¶й—ҙи¶…иҝҮ500msпјҢиҝӣе…Ҙй•ҝжҢүеҝ«иҝӣзҠ¶жҖҒ
                if (touchDuration > 500) {
                    isLongPress = true;
                    // еңЁй•ҝжҢүзҠ¶жҖҒдёӢпјҢж №жҚ®ж»‘еҠЁи·қзҰ»еҝ«иҝӣ
                    const deltaX = e.changedTouches[0].clientX - touchStartX;
                    const duration = video.duration;
                    const seekTime = video.currentTime + (deltaX / 100); // жҜҸж»‘еҠЁ100pxеҝ«иҝӣ1з§’
                    video.currentTime = Math.min(Math.max(seekTime, 0), duration);
                } else {
                    isLongPress = false;
                }
            });

            // йҳІжӯўй»ҳи®ӨиЎҢдёәпјҲеҰӮйЎөйқўж»ҡеҠЁпјү
            video.addEventListener('touchmove', (e) => {
                e.preventDefault();
            });
        </script>
    </body>
</html>`

