    // е»¶иҝҹжү§иЎҢпјҢзЎ®дҝқйЎөйқўеҠ иҪҪе®ҢжҲҗ
    setTimeout(function() {
        // жҹҘжүҫжүҖжңүж–Үжң¬иҠӮзӮ№пјҢеҜ»жүҫж•°еӯҰй—®йўҳ
        const walker = document.createTreeWalker(
