  });

  // зӮ№еҮ»дәӢд»¶зӣ‘еҗ¬еҷЁ
  backToTopBtn.addEventListener("click", () => {
    window.scrollTo({
      top: 0,
      behavior: "smooth"
    });
  });
})();
</script>
