function toByteArray(input) {
  var out = new Packages.java.io.ByteArrayOutputStream();
  var buffer = java.strToBytes('\0'.repeat(4096));
  var bytesRead;
  while ((bytesRead = input.read(buffer)) != -1) {
    out.write(buffer, 0, bytesRead);
  }
  return out.toByteArray();
}

(function() {
  if (src.endsWith('.gif')) {
    return toByteArray(result);
  }

  // йқһGIFж–Үд»¶з»§з»ӯиө°AESи§ЈеҜҶйҖ»иҫ‘
  var keyBytes = "102_53_100_57_54_53_100_102_55_53_51_51_54_50_55_48"
    .split('_')
    .map(c => parseInt(c, 10));

  var ivBytes = "57_55_98_54_48_51_57_52_97_98_99_50_102_98_101_49"
    .split('_')
    .map(c => parseInt(c, 10));

  return java.createSymmetricCrypto(
    "AES/CBC/PKCS5Padding", 
    keyBytes,
    ivBytes
  ).decrypt(result);
})();

